const fastify = require('fastify')({ logger: true });
const crypto = require('crypto');
const rawBody = require('fastify-raw-body');

fastify.register(rawBody, {
  field: 'rawBody',
  global: false,
  encoding: 'utf8',
  runFirst: true
});

fastify.post('/webhook', { config: { rawBody: true } }, async (request, reply) => {
  const signature = request.headers['x-prembly-signature'];

  if (!signature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  const secret = process.env.PREMBLY_API_KEY || '';
  const payload = request.rawBody || '';

  const expectedSignature = crypto
    .createHmac('sha256', secret)
    .update(payload)
    .digest('base64');

  if (signature !== expectedSignature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  return reply.status(200).send({ status: 'received' });
});

const start = async () => {
  try {
    await fastify.listen({ port: 3000, host: '0.0.0.0' });
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

start();

