const crypto = require('crypto');

// Save raw body
fastify.addHook('preValidation', async (request, reply) => {
  // fastify doesn't expose raw body by default easily without plugins if parsed, 
  // but let's just use a custom content type parser for application/json to keep the raw body.
});

// Actually, the easiest way to get raw body in fastify for a specific route is to use a custom content type parser.
fastify.removeAllContentTypeParsers();
fastify.addContentTypeParser('*', { parseAs: 'buffer' }, function (request, payload, done) {
  done(null, payload);
});

fastify.post('/webhook', async (request, reply) => {
  const signature = request.headers['x-prembly-signature'];

  if (!signature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  const secret = process.env.PREMBLY_API_KEY || '';
  const payload = request.body ? request.body.toString('utf8') : '';

  const expectedSignature = crypto
    .createHmac('sha256', secret)
    .update(payload)
    .digest('base64');

  if (signature !== expectedSignature) {
    return reply.status(401).send({ error: 'Invalid signature' });
  }

  return reply.status(200).send({ status: 'received' });
});

const start = async () => {
  try {
    await fastify.listen({ port: 3000, host: '0.0.0.0' });
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

